e":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"a37165d6-b6e3-415c-8387-e895a6f2abfa"},{"version":"CommandV1","origId":1083584440950562,"guid":"ef389d6b-7824-4d94-97cf-985f3a392884","subtype":"command","commandType":"auto","position":7.0,"command":"%sql\nCREATE DATABASE IF NOT EXISTS aqe_demo_db;\nUSE aqe_demo_db;\n\nDROP TABLE IF EXISTS items;\nDROP TABLE IF EXISTS sales;\n\n-- Create \"items\" table.\n\nCREATE TABLE items\nUSING parquet\nAS\nSELECT id AS i_item_id,\nCAST(rand() * 1000 AS INT) AS i_price\nFROM RANGE(30000000);\n\n-- Create \"sales\" table with skew.\n-- Item with id 100 is in 80% of all sales.\n\nCREATE TABLE sales\nUSING parquet\nAS\nSELECT CASE WHEN rand() < 0.8 THEN 100 ELSE CAST(rand() * 30000000 AS INT) END AS s_item_id,\nCAST(rand() * 100 AS INT) AS s_quantity,\nDATE_ADD(current_date(), - CAST(rand() * 360 AS INT)) AS s_date\nFROM RANGE(1000000000);","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"9722a379-7b4b-41c8-b106-5b54e9581ed7"},{"version":"CommandV1","origId":1083584440950563,"guid":"ca8d7511-7b9f-4b83-a38e-fee86b4596ba","subtype":"command","commandType":"auto","position":8.0,"command":"%md\n## Dynamically Coalesce Shuffle Partitions","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"89a61954-c086-4920-9b4a-5ac855eb05b9"},{"version":"CommandV1","origId":1083584440950564,"guid":"f9bbcfc8-ee2c-49bd-9f86-8f62ac6ae974","subtype":"command","commandType":"auto","position":9.0,"command":"%sql\n-- Get the sums of sales quantity grouped by sales date.\n-- The grouped result is very small.\n\nSELECT s_date, sum(s_quantity) AS q\nFROM sales\nGROUP BY s_date\nORDER BY q DESC;","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"e0a6f198-4a62-4058-9efe-b9402f686242"},{"version":"CommandV1","origId":1083584440950565,"guid":"afd56311-fda7-4cc0-855a-f49f416a6914","subtype":"command","commandType":"auto","position":10.0,"command":"%md\n* The partition sizes after aggregation are very small: 13KB on average, 431KB in total (see the highlighted box **shuffle bytes written**).\n* AQE combines these small partitions into one new partition (see the highlighted box **CustomShuffleReader**).\n\n![screenshot_coalesce](https://docs.databricks.com/_static/images/spark/aqe/coalesce_partitions.png)","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"b62a15dc-4b59-44b9-995a-87f379949bbc"},{"version":"CommandV1","origId":1083584440950566,"guid":"2445e1ab-f9c2-47e4-8c26-1d7b63a227df","subtype":"command","commandType":"auto","position":11.0,"command":"%md\n## Dynamically Switch Join Strategies","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"c35a9348-991b-439b-9144-57679cb2ede0"},{"version":"CommandV1","origId":1083584440950567,"guid":"ae688dbf-9657-4e0e-8c96-744ddc5c0a51","subtype":"command","commandType":"auto","position":12.0,"command":"%sql\n-- Get total sales amount grouped by sales date for items with a price lower than 10.\n-- The selectivity of the filter by price is not known in static planning, so the initial plan opts for sort merge join.\n-- But in fact, the \"items\" table after filtering is very small, so the query can do a broadcast hash join instead.\n\n-- Static explain shows the initial plan with sort merge join.\n\nEXPLAIN\nSELECT s_date, sum(s_quantity * i_price) AS total_sales\nFROM sales\nJOIN items ON s_item_id = i_item_id\nWHERE i_price < 10\nGROUP BY s_date\nORDER BY total_sales DESC;","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"992827a6-8223-4e8b-9cf2-59ea2cec0c11"},{"version":"CommandV1","origId":1083584440950568,"guid":"613fb843-fff7-4089-b54e-acd6bb3e31b4","subtype":"command","commandType":"auto","position":13.0,"command":"%sql\n-- The runtime join strategy is changed to broadcast hash join.\n\nSELECT s_date, sum(s_quantity * i_price) AS total_sales\nFROM sales\nJOIN items ON s_item_id = i_item_id\nWHERE i_price < 10\nGROUP BY s_date\nORDER BY total_sales DESC;","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"4ee210ad-2398-4bcd-96f3-76caaebb966f"},{"version":"CommandV1","origId":1083584440950569,"guid":"7752e66a-2eab-4740-9243-92d8d9eecc3c","subtype":"command","commandType":"auto","position":14.0,"command":"%md\n* The data size of the \"items\" table after filtering is very small 6.9 MB (see the highlighted box **data size**).\n*  AQE changes the sort merge join to broadcast hash join at runtime (see the highlighted box **BroadcastHashJoin**).\n\n![screenshot_strategy](https://docs.databricks.com/_static/images/spark/aqe/join_strategy.png)","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"495b6f7f-b52f-40d6-883f-f31c58d6228a"},{"version":"CommandV1","origId":1083584440950570,"guid":"1a385949-eea0-4813-813b-2efe786d4870","subtype":"command","commandType":"auto","position":15.0,"command":"%md\n\n## Dynamically Optimize Skew Join","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"0d8957b8-940a-456a-b23a-25f51f2e3a0b"},{"version":"CommandV1","origId":1083584440950571,"guid":"7ee2c0d9-53cc-4089-a2ac-44f271af3c53","subtype":"command","commandType":"auto","position":16.0,"command":"%sql\n-- Get the total sales amount grouped by sales date.\n-- The partition in the \"sales\" table containing value \"100\" as \"s_item_id\" is much larger than other partitions.\n-- AQE splits the skewed partition into smaller partitions before joining the \"sales\" table with the \"items\" table.\n\nSELECT s_date, sum(s_quantity * i_price) AS total_sales\nFROM sales\nJOIN items ON i_item_id = s_item_id\nGROUP BY s_date\nORDER BY total_sales DESC;","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"4c0457de-c94e-41c9-a08d-99dc0ee7daea"},{"version":"CommandV1","origId":1083584440950572,"guid":"f4c3d6f2-0346-4da2-a4ca-3df9da9e22bb","subtype":"command","commandType":"auto","position":17.0,"command":"%md\n* There is a skewed partition from the \"sales\" ta